using UnityEngine;

/// <summary>
/// Comportamento de água de um inimigo (Enemy Creator — Etapa 3.1).
///
/// Reutiliza o WaterDetector partilhado com o player (Player/WaterDetector.cs)
/// para saber IsInWater/IsSubmerged/IsAtSurface, e aplica as regras de
/// <see cref="EnemyData.water"/> (EnemyWaterConfig):
///
/// - Terrestre (default) que cai na água: após "fallInWaterDelay", aplica
///   "fallInWaterReaction" (Morre/Desactiva/Nenhuma).
/// - Nadador ("canSwim"): gravidade anulada dentro de água; se não tiver
///   "canDive" e submergir, é empurrado de volta para a superfície.
/// - Mergulhador ("canDive"): move-se livremente debaixo de água.
/// - Aquático com "diesOutOfWater": após "outOfWaterDelay" fora de água,
///   aplica "outOfWaterReaction".
/// - "swimSpeed" &gt; 0 limita a velocidade do Rigidbody2D dentro de água.
///
/// O movimento de perseguição/patrulha continua a ser do EnemyMovement
/// (tipos Nadador/Mergulhador = movimento livre em X/Y); este componente só
/// corrige o resultado (superfície, limite de velocidade) e gere vida/estado.
/// Os ataques aquáticos (Etapa 3.2) lêem este componente via
/// EnemyAttackController.
/// </summary>
[DisallowMultipleComponent]
[RequireComponent(typeof(EnemyController))]
[DefaultExecutionOrder(50)] // corre depois de EnemyMovement, para poder corrigir a velocidade
public class EnemyWaterBehavior : MonoBehaviour
{
    [Header("Detecção de Água")]
    [Tooltip("WaterDetector deste inimigo (auto-detectado; criado automaticamente se não existir).")]
    [SerializeField] private WaterDetector waterDetector;

    [Tooltip("Layers consideradas água. Usado apenas se o WaterDetector for criado automaticamente (senão, vale o do próprio WaterDetector).")]
    public LayerMask waterLayer;

    private EnemyController _controller;
    private EnemyHealth _health;

    private float _inWaterTimer;
    private float _outOfWaterTimer;
    private float _gravityScaleOutOfWater;
    private bool _wasInWater;

    /// <summary>Config de água do EnemyData (null se "data" não estiver definido).</summary>
    public EnemyWaterConfig Config => _controller != null && _controller.Data != null ? _controller.Data.water : null;

    /// <summary>True se o inimigo está em água (qualquer profundidade).</summary>
    public bool IsInWater => waterDetector != null && waterDetector.IsInWater;

    /// <summary>True se o inimigo está completamente debaixo de água (cabeça submersa).</summary>
    public bool IsSubmerged => waterDetector != null && waterDetector.IsSubmerged;

    /// <summary>True se o inimigo está em água mas com a cabeça de fora.</summary>
    public bool IsAtSurface => waterDetector != null && waterDetector.IsAtSurface;

    private void Awake()
    {
        _controller = GetComponent<EnemyController>();
        _health = GetComponent<EnemyHealth>();

        if (waterDetector == null)
            waterDetector = GetComponent<WaterDetector>();

        if (waterDetector == null)
        {
            waterDetector = gameObject.AddComponent<WaterDetector>();
            waterDetector.waterLayer = waterLayer;
        }
    }

    private void Start()
    {
        // Lido em Start (e não Awake) para apanhar o gravityScale já ajustado
        // por EnemyMovement (tipos de movimento livre põem-no a 0 em Awake).
        if (_controller.Rb != null)
            _gravityScaleOutOfWater = _controller.Rb.gravityScale;
    }

    private void Update()
    {
        var cfg = Config;
        if (cfg == null || _controller.IsTerminal) return;

        if (IsInWater)
        {
            _outOfWaterTimer = 0f;

            // Terrestre que caiu na água (GDD: "morre ao cair na água caso não saiba nadar?").
            if (!cfg.canSwim)
            {
                _inWaterTimer += Time.deltaTime;
                if (_inWaterTimer >= cfg.fallInWaterDelay)
                    ApplyReaction(cfg.fallInWaterReaction);
            }
        }
        else
        {
            _inWaterTimer = 0f;

            // Aquático fora de água (GDD: "morre fora da água?").
            if (cfg.diesOutOfWater)
            {
                _outOfWaterTimer += Time.deltaTime;
                if (_outOfWaterTimer >= cfg.outOfWaterDelay)
                    ApplyReaction(cfg.outOfWaterReaction);
            }
        }
    }

    private void FixedUpdate()
    {
        var cfg = Config;
        var rb = _controller.Rb;
        if (cfg == null || rb == null || _controller.IsTerminal) return;

        bool inWater = IsInWater;

        // Transição terra <-> água: nadadores ficam sem gravidade dentro de água
        // (cobre anfíbios com movimento Terrestre que também sabem nadar).
        if (inWater != _wasInWater)
        {
            if (cfg.canSwim)
                rb.gravityScale = inWater ? 0f : _gravityScaleOutOfWater;

            _wasInWater = inWater;
        }

        if (!inWater || !cfg.canSwim) return;

        // Nadador sem "Mergulha": se submergir, é empurrado de volta à superfície.
        if (!cfg.canDive && IsSubmerged && cfg.floatToSurfaceSpeed > 0f)
            rb.linearVelocity = new Vector2(rb.linearVelocity.x, Mathf.Max(rb.linearVelocity.y, cfg.floatToSurfaceSpeed));

        // Não pode sair da água (Etapa 3.2): trava a subida quando já está à superfície.
        if (!cfg.canLeaveWater && IsAtSurface)
            rb.linearVelocity = new Vector2(rb.linearVelocity.x, Mathf.Min(rb.linearVelocity.y, 0f));

        // Limite de velocidade dentro de água. Durante Atacando, quem manda é o
        // próprio ataque (EnemyAttack.attackSwimSpeed — Etapa 3.2).
        if (cfg.swimSpeed > 0f && _controller.State != EnemyState.Atacando)
            rb.linearVelocity = Vector2.ClampMagnitude(rb.linearVelocity, cfg.swimSpeed);
    }

    /// <summary>Aplica uma EnemyWaterReaction (Morre via EnemyHealth.Kill, que respeita "canOnlyBeDeactivated"; Desactiva via SetState).</summary>
    private void ApplyReaction(EnemyWaterReaction reaction)
    {
        switch (reaction)
        {
            case EnemyWaterReaction.Morre:
                if (_health != null) _health.Kill();
                else _controller.SetState(EnemyState.Morto);
                break;

            case EnemyWaterReaction.Desactiva:
                _controller.SetState(EnemyState.Desactivado);
                break;

            // Nenhuma: não faz nada (ex: robô à prova de água que só se afunda).
        }
    }
}
